#include<bits/stdc++.h>
using namespace std;
int a[110],b[110][110];
int mysqrt(int x)
{
    int tmp=(int)(floor(sqrt(x)));
    while(tmp*tmp>x)
    {
        tmp--;
    }
    while((tmp+1)*(tmp+1)<=x)
    {
        tmp++;
    }
    return tmp;
}
bool check(int x,int y)
{
    int tmp=x+y,s=mysqrt(x+y);
    return s*s==tmp;
}
int main()
{
    int n;
    scanf("%d",&n);
    int k=0;
    for(int i=1;;i++)
    {
        int flag=0;
        for(int j=1;j<=k;j++)
        {
            if(check(b[j][a[j]],i))
            {
                flag=1;
                b[j][++a[j]]=i;
                break;
            }
        }
        if(!flag)
        {
            if(k==n)
            {
                printf("%d\n",i-1);
                break;
            }
            k++;
            b[k][++a[k]]=i;
        }
    }
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=a[i];j++)
        {
            printf("%d ",b[i][j]);
        }
        printf("\n");
    }
    return 0;
}
